// Build Gemini API request body from Worker-provided prompts.
// The Worker already constructs systemPrompt and userPrompt
// with all scenario context, conversation history, and instructions.
// This node simply formats them into the Gemini API structure.

const body = $input.first().json.body;
const action = body.action;
const systemPrompt = body.systemPrompt;
const userPrompt = body.userPrompt;

// Temperature varies by action type:
// - start: higher creativity for diverse scenarios (0.9)
// - message: balanced for realistic conversation + analysis (0.7)
// - reflect: lower for consistent, empathetic analysis (0.5)
const temperatureMap = { start: 0.9, message: 0.7, reflect: 0.5 };
const temperature = temperatureMap[action] || 0.7;

return [{
  json: {
    requestBody: {
      contents: [
        {
          role: 'user',
          parts: [{ text: userPrompt }]
        }
      ],
      systemInstruction: {
        parts: [{ text: systemPrompt }]
      },
      generationConfig: {
        temperature,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 4096,
        responseMimeType: 'application/json'
      }
    },
    action
  }
}];

// Extract Gemini response text, parse JSON, and validate structure.
// The expected JSON schema depends on the action type:
//
// ACTION: start
// { scenarioConfig: {...}, firstMessage: string }
//
// ACTION: message
// { behaviorScores: {...}, shouldInterrupt: bool, nextPhase: string, aiMessage: string }
//
// ACTION: reflect
// { aiAnalysis: string, nextQuestion: string|null, insightSummary?: string }

const geminiResponse = $input.first().json;
const action = $node['Build Gemini Request'].json.action;

// Step 1: Extract generated text
let rawText;
try {
  rawText = geminiResponse.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error(`Gemini response missing expected structure: ${JSON.stringify(geminiResponse).slice(0, 500)}`);
}

if (!rawText || typeof rawText !== 'string') {
  throw new Error('Gemini returned empty or non-string text');
}

// Step 2: Strip markdown fences defensively
let cleaned = rawText.trim();
if (cleaned.startsWith('```json')) cleaned = cleaned.slice(7);
if (cleaned.startsWith('```')) cleaned = cleaned.slice(3);
if (cleaned.endsWith('```')) cleaned = cleaned.slice(0, -3);
cleaned = cleaned.trim();

// Step 3: Parse JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse Gemini JSON: ${e.message}. Raw: ${cleaned.slice(0, 300)}`);
}

// Step 4: Validate based on action type
const errors = [];

if (action === 'start') {
  if (!parsed.scenarioConfig || typeof parsed.scenarioConfig !== 'object') {
    errors.push('Missing scenarioConfig object');
  } else {
    const sc = parsed.scenarioConfig;
    if (!sc.scenarioId) errors.push('Missing scenarioConfig.scenarioId');
    if (!sc.attackType) errors.push('Missing scenarioConfig.attackType');
    if (!sc.difficulty) errors.push('Missing scenarioConfig.difficulty');
    if (!sc.trainingTarget) errors.push('Missing scenarioConfig.trainingTarget');
    if (!sc.scammerPersona || !sc.scammerPersona.name) errors.push('Missing scammerPersona.name');
    if (!sc.scammerPersona || !sc.scammerPersona.role) errors.push('Missing scammerPersona.role');
    if (!sc.scammerPersona || !sc.scammerPersona.tone) errors.push('Missing scammerPersona.tone');
    // Ensure numeric fields have defaults
    if (typeof sc.interruptThreshold !== 'number') sc.interruptThreshold = 70;
    if (typeof sc.minTurnsBeforeInterrupt !== 'number') sc.minTurnsBeforeInterrupt = 3;
  }
  if (!parsed.firstMessage || typeof parsed.firstMessage !== 'string') {
    errors.push('Missing or invalid firstMessage');
  }
}

if (action === 'message') {
  if (!parsed.behaviorScores || typeof parsed.behaviorScores !== 'object') {
    errors.push('Missing behaviorScores object');
  } else {
    const bs = parsed.behaviorScores;
    for (const key of ['activation', 'impulsivity', 'verification', 'awareness', 'riskScore']) {
      if (typeof bs[key] !== 'number' || bs[key] < 0 || bs[key] > 100) {
        errors.push(`behaviorScores.${key} must be a number 0-100 (got ${bs[key]})`);
      }
    }
  }
  if (typeof parsed.shouldInterrupt !== 'boolean') {
    errors.push('Missing or invalid shouldInterrupt (must be boolean)');
  }
  if (!['P1', 'P2', 'P3'].includes(parsed.nextPhase)) {
    errors.push(`Invalid nextPhase: ${parsed.nextPhase} (must be P1, P2, or P3)`);
  }
  if (!parsed.aiMessage || typeof parsed.aiMessage !== 'string') {
    errors.push('Missing or invalid aiMessage');
  }
}

if (action === 'reflect') {
  if (!parsed.aiAnalysis || typeof parsed.aiAnalysis !== 'string') {
    errors.push('Missing or invalid aiAnalysis');
  }
  // nextQuestion can be null (last step) or string
  if (parsed.nextQuestion !== null && typeof parsed.nextQuestion !== 'string') {
    errors.push('nextQuestion must be string or null');
  }
}

if (errors.length > 0) {
  throw new Error(`Validation failed (${action}): ${errors.join('; ')}`);
}

return [{ json: parsed }];
